LA CONTRAPARTIDA EN DINERO DEL CONVINIENTE.',0,1,0,1,NULL,NULL,1,1,1,0,1,5,N'PA05',N'PRESENCIAL,PRESENCIAL HÍBRIDA,PAT,VIRTUAL');
INSERT INTO RUBRO (RUBROID,CONVOCATORIAIDRUBRO,RUBROCODIGO,RUBRONOMBRE,RUBRODESCRIPCION,RUBROTOPE,RUBROAF,RUBROPROYECTO,TIPOUNIDADID,RUBROCANTIDADBENEF,RUBROPORCENTAJE,FORMULAASOCIADA,RUBROPERFILUT,RUBROACTIVO,RUBROTRANSFERENCIA,RUBROINTERNACIONAL,RUBROCASO,RUBROPAQUETE,RUBROMODALIDAD) VALUES (400,10,N'R014',N'R014 ALIMENTACIÓN Y TRANSPORTE PARA BENEFICIARIOS DEL SECTOR AGROPECUARIO.  ',N'ALIMENTACIÓN Y TRANSPORTE PARA BENEFICIARIOS DEL SECTOR AGROPECUARIO. DE
CONFORMIDAD CON LO DISPUESTO EN EL PARÁGRAFO 1 DEL ARTÍCULO 19 DEL ACUERDO 0007 DE 2021, “PARA EL
CASO DE PROYECTOS CUYOS BENEFICIARIOS DE LAS ACCIONES DE FORMACIÓN SEAN PRODUCTORES DEL SECTOR
AGROPECUARIO, PODRÁN INCLUIR EL RUBRO MANUTENCIÓN (ALIMENTACIÓN) Y EL RUBRO TRANSPORTE LOCAL, PARA LOS
BENEFICIARIOS DE LA CAPACITACIÓN. ESTOS RUBROS DEBEN ESTAR A CARGO DE LA CONTRAPARTIDA DEL CONVINIENTE.
EN NINGÚN CASO EL VALOR DE ESTE RUBRO PODRÁ SUPERAR EL CINCUENTA POR CIENTO (50%) DEL VALOR TOTAL DE LA
CONTRAPARTIDA DE LA ACCIÓN DE FORMACIÓN.”',0,1,0,1,NULL,NULL,1,1,1,0,1,5,N'PA05',N'PRESENCIAL,PRESENCIAL HÍBRIDA,PAT,VIRTUAL');
INSERT INTO RUBRO (RUBROID,CONVOCATORIAIDRUBRO,RUBROCODIGO,RUBRONOMBRE,RUBRODESCRIPCION,RUBROTOPE,RUBROAF,RUBROPROYECTO,TIPOUNIDADID,RUBROCANTIDADBENEF,RUBROPORCENTAJE,FORMULAASOCIADA,RUBROPERFILUT,RUBROACTIVO,RUBROTRANSFERENCIA,RUBROINTERNACIONAL,RUBROCASO,RUBROPAQUETE,RUBROMODALIDAD) VALUES (401,10,N'R015',N'R015: TRANSFERENCIA DE CONOCIMIENTO Y TECNOLOGÍA',N'TRANSFERENCIA DE CONOCIMIENTO Y TECNOLOGÍA. SE ENTIENDE COMO EL PROCESO DE APROPIACIÓN
E INCORPORACIÓN DE CONOCIMIENTOS, TECNOLOGÍAS Y DE NUEVAS PRÁCTICAS, GENERADAS EN LOS PROYECTOS
EJECUTADOS EN EL MARCO DEL PROGRAMA DE FORMACIÓN CONTINUA ESPECIALIZADA, COMO EJERCICIO DE
EXTENSIÓN DE LA ACTIVIDAD FORMATIVA DE CADA UNO DE LOS CONVENIOS SUSCRITOS, EN FAVOR DE LA COMUNIDAD
SENA, AGENTES DEL SISTEMA NACIONAL DE CIENCIA, TECNOLOGÍA E INNOVACIÓN Y DEL PERSONAL QUE DEFINA LA ENTIDAD, QUIENES ACTUARÁN COMO RECEPTORES, GENERADORES Y SOCIALIZADORES DE LAS NUEVAS PRÁCTICAS Y CONOCIMIENTOS.
EL PORCENTAJE DE TRANSFERENCIA DE CONOCIMIENTO ESTARÁ A CARGO DE LA CONTRAPARTIDA EN DINERO DEL
CONVINIENTE Y SE ESTABLECERÁ SOBRE EL VALOR TOTAL DE LAS ACCIONES DE FORMACIÓN DEL PROYECTO, CONFORME
LO SEÑALA EL NUMERAL 15 DEL ARTÍCULO 19 DEL ACUERDO 007 DE 2021 Y LAS CONDICIONES QUE SE FIJEN EN EL
RESPECTIVO PLIEGO DE LA CONVOCATORIA.',0,0,1,1,NULL,NULL,1,1,1,1,1,5,N'ME01',N'Caso05');

COMMIT;
